operations.insert:
/* Rounded button-like lower tabs */
.stacked-panels {
  grid-template-columns: repeat(3, minmax(0, 1fr)) !important;
  column-gap: 14px !important;
  row-gap: 12px !important;
  justify-items: center !important;
  align-items: center !important;
  margin-top: 16px !important;
  border-bottom: 0 !important;
}

.stacked-panels .accordion-toggle {
  width: auto !important;
  min-width: 235px !important;
  max-width: 100% !important;
  min-height: 54px !important;
  margin: 0 !important;
  padding: 11px 18px !important;
  border-radius: 999px !important;
  border: 1px solid #d7e1ec !important;
  background: #f5f8fb !important;
  color: #41556a !important;
  justify-content: center !important;
  text-align: center !important;
  box-shadow: 0 8px 20px rgba(8, 20, 34, 0.035) !important;
  opacity: 0.92;
}

.stacked-panels .accordion-toggle > span:first-child {
  text-align: center !important;
}

.stacked-panels .accordion-toggle:hover {
  background: #ffffff !important;
  color: #14283f !important;
  border-color: #c6d5e5 !important;
  box-shadow: 0 12px 26px rgba(8, 20, 34, 0.06) !important;
  opacity: 1;
}

.stacked-panels .accordion.open .accordion-toggle {
  background: #eaf4ff !important;
  color: #0b4f91 !important;
  border-color: rgba(11, 92, 171, 0.32) !important;
  box-shadow: 0 12px 30px rgba(11, 92, 171, 0.13) !important;
  opacity: 1;
  z-index: 4 !important;
}

.stacked-panels .accordion-meta {
  margin-top: 2px !important;
  font-size: 11px !important;
  line-height: 1.15 !important;
  color: #748397 !important;
}

.stacked-panels .accordion.open .accordion-meta {
  color: #326da4 !important;
}

.stacked-panels #advancedTools:not(.open) .accordion-toggle {
  background: #f7f9fc !important;
  color: #657486 !important;
  opacity: 0.82;
}

.stacked-panels .accordion-body {
  grid-column: 1 / -1 !important;
  grid-row: 2 !important;
  width: 100% !important;
  margin-top: 2px !important;
  padding: 16px !important;
  border: 1px solid #d6e0eb !important;
  border-radius: 18px !important;
  background: #ffffff !important;
  box-shadow: 0 18px 40px rgba(8, 20, 34, 0.045) !important;
}

@media (max-width: 980px) {
  .stacked-panels .accordion-toggle {
    min-width: 190px !important;
    padding-inline: 14px !important;
  }
}

@media (max-width: 760px) {
  .stacked-panels {
    grid-template-columns: 1fr !important;
    justify-items: stretch !important;
    gap: 8px !important;
  }

  .stacked-panels .accordion-toggle {
    width: 100% !important;
    min-width: 0 !important;
    border-radius: 16px !important;
  }

  .stacked-panels .accordion-body {
    margin-top: 0 !important;
    border-radius: 16px !important;
  }
}
